# Flask slash command handler
from flask import Flask, request, jsonify
import anthropic, os, threading

app = Flask(__name__)
client = anthropic.Anthropic(api_key=os.environ['ANTHROPIC_API_KEY'])
SLACK_TOKEN = os.environ['SLACK_BOT_TOKEN']

def respond_async(response_url: str, question: str, system_prompt: str):
    import requests
    message = client.messages.create(
        model='claude-haiku-4-5-20251001',  # Haiku for low-latency Slack responses
        max_tokens=800,
        system=system_prompt,
        messages=[{'role': 'user', 'content': question}]
    )
    requests.post(response_url, json={
        'response_type': 'in_channel',
        'text': message.content[0].text
    })

@app.route('/slack/ask-claude', methods=['POST'])
def slash_command():
    question = request.form.get('text', '')
    response_url = request.form.get('response_url')
    if not question:
        return jsonify({'text': 'Usage: /ask-claude [your question]'})
    # Respond immediately (Slack requires < 3s), then call API async
    threading.Thread(
        target=respond_async,
        args=(response_url, question,
              'You are a concise assistant. Keep answers under 200 words.')
    ).start()
    return jsonify({'text': 'Thinking...', 'response_type': 'ephemeral'})

if __name__ == '__main__':
    app.run(port=3000)

// Google Apps Script — Claude Docs Add-on
// Add to Extensions > Apps Script in a Google Doc

const ANTHROPIC_KEY = PropertiesService.getScriptProperties()
                        .getProperty('ANTHROPIC_API_KEY');

function onOpen() {
  DocumentApp.getUi()
    .createMenu('Claude')
    .addItem('Improve selected text', 'improveSelection')
    .addItem('Summarise document', 'summariseDoc')
    .addToUi();
}

function callClaude(prompt, systemPrompt) {
  const payload = {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 1024,
    system: systemPrompt,
    messages: [{role: 'user', content: prompt}]
  };
  const options = {
    method: 'post',
    contentType: 'application/json',
    headers: {'x-api-key': ANTHROPIC_KEY, 'anthropic-version': '2023-06-01'},
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };
  const response = UrlFetchApp.fetch(
    'https://api.anthropic.com/v1/messages', options
  );
  const result = JSON.parse(response.getContentText());
  return result.content[0].text;
}

function improveSelection() {
  const doc = DocumentApp.getActiveDocument();
  const selection = doc.getSelection();
  if (!selection) {
    DocumentApp.getUi().alert('Select some text first.');
    return;
  }
  const elements = selection.getRangeElements();
  const text = elements.map(e => e.getElement().asText().getText()).join(' ');
  const improved = callClaude(
    'Improve this text for clarity and conciseness:\n\n' + text,
    'You are a professional editor. Improve the text without changing its meaning. '
    + 'Return only the improved text, no explanation.'
  );
  // Replace selected text
  elements[0].getElement().asText().setText(improved);
}

function summariseDoc() {
  const body = DocumentApp.getActiveDocument().getBody().getText();
  const summary = callClaude(
    'Summarise this document in 3 bullet points:\n\n' + body.substring(0, 8000),
    'You are a summarisation assistant. Return exactly 3 bullet points.'
  );
  DocumentApp.getUi().alert('Summary', summary, DocumentApp.getUi().ButtonSet.OK);
}
